using Microsoft.AspNetCore.Mvc; using ModularMonolith.BuildingBlocks.Errors; using ModularMonolith.Modules.Orders.Api.Requests; using ModularMonolith.Modules.Orders.Application; namespace ModularMonolith.Modules.Orders.Api.Controllers;
[ApiController,Route("api/orders")] public sealed class OrdersController(OrdersService orders):ControllerBase{ [HttpPost] public async Task<ActionResult<CreateOrderResponse>> Create(CreateOrderRequest r,CancellationToken ct)=>this.ToActionResult(await orders.CreateAsync(r.UserId,r.Items.Select(i=>new CreateOrderItem(i.ProductId,i.Quantity)).ToList(),ct)); [HttpGet("{id:guid}")] public async Task<ActionResult<OrderResponse>> Get(Guid id,CancellationToken ct)=>this.ToActionResult(await orders.GetAsync(id,ct)); [HttpGet] public async Task<IReadOnlyCollection<OrderResponse>> List(CancellationToken ct)=>await orders.ListAsync(ct);}
